<?php $requestRows = $rows ?? []; ?>
<div class="table-responsive data-shell"><table class="table modern-table align-middle"><thead><tr><th>Data</th><th>Requisitante</th><th>Equipa</th><th>Artigo</th><th>Armazém</th><th>Qtd</th><th>Entregue</th><th>Estado</th><th>Valor</th><th class="text-end">Ações</th></tr></thead><tbody><?php foreach($requestRows as $r): $remaining=max(0,(float)$r['quantity']-(float)($r['delivered_quantity']??0)); $modalId='deliverRequest'.(int)$r['id']; ?><tr><td><?= htmlspecialchars(substr($r['created_at'],0,10)) ?></td><td><?= htmlspecialchars($r['requester']) ?></td><td><?= htmlspecialchars($r['team']) ?></td><td><strong><?= htmlspecialchars($r['item']) ?></strong></td><td><?= htmlspecialchars($r['warehouse'] ?? '-') ?></td><td><?= htmlspecialchars($r['quantity']) ?></td><td><div class="progress-wrap"><span><strong><?= htmlspecialchars($r['delivered_quantity'] ?? 0) ?></strong> / <?= htmlspecialchars($r['quantity']) ?></span><div class="progress"><div class="progress-bar" style="width: <?= (float)$r['quantity'] > 0 ? min(100, ((float)($r['delivered_quantity'] ?? 0)/(float)$r['quantity'])*100) : 0 ?>%"></div></div><small>faltam <?= $remaining ?></small></div></td><td><span class="badge status-badge status-<?= strtolower($r['status']) ?>"><?= htmlspecialchars($r['status']) ?></span></td><td>€ <?= number_format((float)$r['request_value'],2,',','.') ?></td><td class="text-end"><div class="btn-cluster justify-content-end"><a class="btn btn-sm btn-outline-success" href="<?= \App\Core\Url::page('request_action') ?>&id=<?= $r['id'] ?>&do=approve">Aprovar</a><button type="button" class="btn btn-sm btn-primary" data-bs-toggle="modal" data-bs-target="#<?= $modalId ?>" <?= $remaining<=0?'disabled':'' ?>>Entregar</button><a class="btn btn-sm btn-outline-secondary" href="<?= \App\Core\Url::page('requests') ?>&edit=<?= $r['id'] ?>">Editar</a><a class="btn btn-sm btn-outline-danger" href="<?= \App\Core\Url::page('request_action') ?>&id=<?= $r['id'] ?>&do=cancel">Cancelar</a></div></td></tr><?php endforeach; ?></tbody></table></div>
<?php foreach($requestRows as $r): $remaining=max(0,(float)$r['quantity']-(float)($r['delivered_quantity']??0)); $modalId='deliverRequest'.(int)$r['id']; ?>
<div class="modal fade" id="<?= $modalId ?>" tabindex="-1" aria-hidden="true"><div class="modal-dialog modal-dialog-centered"><form method="post" action="<?= \App\Core\Url::page('request_action') ?>&id=<?= $r['id'] ?>&do=deliver" class="modal-content deliver-modal"><div class="modal-header"><div><span class="eyebrow">Entrega parcial</span><h5 class="modal-title">Entregar <?= htmlspecialchars($r['item']) ?></h5></div><button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Fechar"></button></div><div class="modal-body"><div class="delivery-summary"><div><span>Pedido</span><strong><?= htmlspecialchars($r['quantity']) ?></strong></div><div><span>Já entregue</span><strong><?= htmlspecialchars($r['delivered_quantity'] ?? 0) ?></strong></div><div><span>Por entregar</span><strong><?= $remaining ?></strong></div></div><label class="form-label mt-3">Quantidade a entregar agora</label><input class="form-control form-control-lg" name="deliver_quantity" type="number" min="0.01" max="<?= $remaining ?>" step="0.01" value="<?= $remaining ?>" required><p class="text-muted small mt-2 mb-0">A entrega abate automaticamente o stock do armazém selecionado. Se não entregar tudo, o pedido fica como Parcial.</p></div><div class="modal-footer"><button type="button" class="btn btn-light" data-bs-dismiss="modal">Voltar</button><button class="btn btn-primary">Confirmar entrega</button></div></form></div></div>
